function makeId() {
  if (window.crypto?.randomUUID) return window.crypto.randomUUID();
  return `id-${Date.now()}-${Math.random().toString(16).slice(2)}`;
}

function loadList(key, fallback) {
  const saved = localStorage.getItem(key);
  if (!saved) return fallback;

  try {
    const parsed = JSON.parse(saved);
    return Array.isArray(parsed) ? parsed : fallback;
  } catch {
    return fallback;
  }
}

function saveList(key, list) {
  localStorage.setItem(key, JSON.stringify(list));
}

function bindCategoryInput() {
  if (!photoCategory || !customCategory) return;

  const showCategorySelect = (value = photoCategory.value || "palsoon") => {
    photoCategory.value = value;
    photoCategory.hidden = false;
    customCategory.hidden = true;
    customCategory.value = customCategoryPrompt;
    customCategory.required = false;
  };

  const showCustomCategoryInput = () => {
    photoCategory.hidden = true;
    customCategory.hidden = false;
    customCategory.value = customCategoryPrompt;
    customCategory.required = true;
  };

  if (photoCategory.dataset.categoryBound !== "true") {
    photoCategory.addEventListener("change", () => {
      if (photoCategory.value === "other") showCustomCategoryInput();
    });

    customCategory.addEventListener("focus", () => {
      if (customCategory.value === customCategoryPrompt) customCategory.value = "";
    });

    customCategory.addEventListener("click", () => {
      if (customCategory.value === customCategoryPrompt) customCategory.value = "";
    });

    customCategory.addEventListener("keydown", (event) => {
      if (event.key !== "Escape") return;
      showCategorySelect("other");
    });

    document.addEventListener("click", (event) => {
      const categoryControl = photoCategory.closest(".category-control");
      if (
        customCategory.hidden ||
        categoryControl?.contains(event.target)
      ) {
        return;
      }
      showCategorySelect("other");
    });

    photoCategory.dataset.categoryBound = "true";
  }

  if (photoCategory.value === "other") {
    showCustomCategoryInput();
  } else {
    showCategorySelect();
  }
}

function replaceGrandmotherText(value) {
  return String(value)
    .replaceAll("할머니께", "송순희 여사께")
    .replaceAll("할머니의", "송순희 여사의")
    .replaceAll("할머니", "송순희 여사");
}

function normalizeHonorifics() {
  let albumChanged = false;
  albumItems = albumItems.map((item) => {
    const next = {
      ...item,
      title: replaceGrandmotherText(item.title || ""),
      memo: replaceGrandmotherText(item.memo || ""),
    };
    if (next.title !== item.title || next.memo !== item.memo) albumChanged = true;
    return next;
  });

  let letterChanged = false;
  letters = letters.map((letter) => {
    const next = {
      ...letter,
      from: replaceGrandmotherText(letter.from || ""),
      body: replaceGrandmotherText(letter.body || ""),
    };
    if (next.from !== letter.from || next.body !== letter.body) letterChanged = true;
    return next;
  });

  if (albumChanged) saveList(keys.album, albumItems);
  if (letterChanged) saveList(keys.letters, letters);
}

function normalizeAlbumItems() {
  let changed = false;
  albumItems = albumItems.map((item) => {
    const inferredFamily = item.title?.includes("송순희 여사 팔순잔치")
      ? "song-soonhee"
      : item.family || "song-soonhee";
    const next = {
      ...item,
      family: inferredFamily,
      createdAt: item.createdAt || new Date().toISOString(),
      image: normalizeImagePath(item.image || ""),
      customCategory: item.customCategory || "",
      ...normalizeReactionState(item),
      comments: Array.isArray(item.comments)
        ? item.comments
            .filter((comment) => comment.text !== "테스트 메모입니다.")
            .map((comment) => ({
              ...comment,
              ...normalizeReactionState(comment),
            }))
        : [],
    };
    if (
      next.family !== item.family ||
      next.createdAt !== item.createdAt ||
      next.image !== (item.image || "") ||
      next.customCategory !== (item.customCategory || "") ||
      JSON.stringify(next.reactions) !== JSON.stringify(item.reactions || {}) ||
      next.selectedReaction !== (item.selectedReaction || "") ||
      next.comments !== item.comments
    ) {
      changed = true;
    }
    return next;
  });
  if (changed) saveList(keys.album, albumItems);
}

function normalizeImagePath(image) {
  if (image === "assets/palsoon-hero.png") return defaultImages.palsoon;
  if (image === "assets/birthday-table.png") return defaultImages.birthday;
  if (image === "./assets/palsoon-hero.png") return defaultImages.palsoon;
  if (image === "./assets/birthday-table.png") return defaultImages.birthday;
  if (image === "assets/palsoon-hero-small.jpg") return defaultImages.palsoon;
  if (image === "assets/birthday-table-small.jpg") return defaultImages.birthday;
  if (image === "./assets/palsoon-hero-small.jpg") return defaultImages.palsoon;
  if (image === "./assets/birthday-table-small.jpg") return defaultImages.birthday;
  return image;
}

function getImageFallback(item) {
  if (item.category === "birthday") return defaultImages.birthday;
  return defaultImages.palsoon;
}

function applyImageFallback(img, item) {
  img.addEventListener("error", () => {
    const fallback = getImageFallback(item);
    if (img.src.endsWith(fallback.replace("./", ""))) {
      img.remove();
      return;
    }
    img.src = fallback;
  });
}

function bindImageFallbacks() {
  if (!heroImage) return;
  heroImage.src = defaultImages.palsoon;
  heroImage.addEventListener("error", () => {
    if (heroImage.src === defaultImages.palsoon) return;
    heroImage.src = defaultImages.palsoon;
  });
  window.setTimeout(() => {
    if (!heroImage.complete || heroImage.naturalWidth > 0) return;
    heroImage.src = defaultImages.palsoon;
  }, 200);
}

function normalizeReactionState(target) {
  const reactions = {};
  reactionTypes.forEach((reaction) => {
    reactions[reaction.key] = Math.max(
      0,
      Number(target.reactions?.[reaction.key] || 0)
    );
  });

  if (!target.reactions && Number.isFinite(target.likes) && target.likes > 0) {
    reactions.heart = target.likes;
  }

  return {
    reactions,
    selectedReaction: reactionTypes.some(
      (reaction) => reaction.key === target.selectedReaction
    )
      ? target.selectedReaction
      : "",
  };
}

function bindFamilyTabs() {
  familyTabs.forEach((tab) => {
    tab.addEventListener("click", () => {
      selectedFamily = tab.dataset.family;
      familyTabs.forEach((item) => item.classList.toggle("active", item === tab));
      updateFamilyView();
      renderAlbum();
      renderStoryPhotos();
    });
  });
}

function updateFamilyView() {
  const label = familyLabels[selectedFamily] || familyLabels.all;
  heroTitle.textContent = `${label} 환영합니다`;
  if (storyTitle) storyTitle.textContent = `${label} 이야기`;

  const familySelect = document.querySelector("#photoFamily");
  if (familySelect && selectedFamily !== "all") {
    familySelect.value = selectedFamily;
  }
}

function formatDate(date) {
  if (!date) return "날짜 미정";
  return new Intl.DateTimeFormat("ko-KR", {
    year: "numeric",
    month: "long",
    day: "numeric",
    weekday: "short",
  }).format(new Date(`${date}T00:00`));
}

function getReactionTotal(target) {
  return Object.values(normalizeReactionState(target).reactions).reduce(
    (sum, count) => sum + count,
    0
  );
}

function getCommentReactionTotal(item) {
  return (item.comments || []).reduce(
    (sum, comment) => sum + getReactionTotal(comment),
    0
  );
}

function getPopularityScore(item) {
  return getReactionTotal(item) + getCommentReactionTotal(item);
}

function getCategoryLabel(item) {
  if (item.category === "other" && item.customCategory) return item.customCategory;
  return categoryLabels[item.category] || "기타";
}

function normalizeCategoryInput(value) {
  return {
    category: value || "other",
    customCategory: "",
  };
}

function getSelectedCategoryInput() {
  if (!customCategory?.hidden) {
    const label = customCategory.value.trim();
    return {
      category: "other",
      customCategory: label === customCategoryPrompt ? "" : label,
    };
  }

  return normalizeCategoryInput(photoCategory.value);
}

function renderAlbum() {
  albumGrid.innerHTML = "";

  const visibleItems = getVisibleAlbumItems();
  visibleItems.forEach((item) => {
    const card = document.createElement("article");
    card.className = "album-card";

    const media = document.createElement("div");
    media.className = "album-media";
    if (item.image?.startsWith("gradient:")) {
      media.style.background = item.image.replace("gradient:", "");
    } else if (item.image) {
      const img = document.createElement("img");
      img.src = item.image;
      img.alt = `${item.title} 사진`;
      applyImageFallback(img, item);
      media.append(img);
    }

    const hasText = Boolean(item.title || item.date || item.memo);
    if (hasText && (item.category || item.family)) {
      const tag = document.createElement("span");
      tag.className = "event-tag";
      tag.textContent = item.family ? familyLabels[item.family] : getCategoryLabel(item);
      media.append(tag);
    }

    const body = document.createElement("div");
    body.className = "album-body";

    if (item.date) {
      const date = document.createElement("time");
      date.textContent = formatDate(item.date);
      body.append(date);
    }
    if (item.title) {
      const title = document.createElement("h3");
      title.textContent = item.title;
      body.append(title);
    }
    if (item.memo) {
      const memo = document.createElement("p");
      memo.textContent = item.memo;
      body.append(memo);
    }

    card.append(media);
    if (hasText) card.append(body);
    card.append(createAlbumActions(item));
    card.append(createCommentArea(item));
    albumGrid.append(card);
  });

  if (!visibleItems.length) {
    const empty = document.createElement("article");
    empty.className = "empty-state";
    empty.textContent = "아직 이 가족 앨범에 업로드된 사진이 없습니다.";
    albumGrid.append(empty);
  }
}

function createAlbumActions(item) {
  const actions = document.createElement("div");
  actions.className = "album-actions";

  const reactions = createReactionButtons(item, (reactionKey) => {
    toggleAlbumReaction(item.id, reactionKey);
  });

  const shareButton = document.createElement("button");
  shareButton.className = "action-button";
  shareButton.type = "button";
  shareButton.textContent = "공유";
  shareButton.addEventListener("click", () => shareAlbumItem(item));

  const downloadButton = document.createElement("a");
  downloadButton.className = "action-button";
  downloadButton.textContent = "다운로드";
  downloadButton.href = item.image?.startsWith("gradient:") ? "#" : item.image || "#";
  downloadButton.download = `${item.title || "family-photo"}.png`;
  if (!item.image || item.image.startsWith("gradient:")) {
    downloadButton.setAttribute("aria-disabled", "true");
    downloadButton.addEventListener("click", (event) => event.preventDefault());
  }

  actions.append(reactions, shareButton, downloadButton);
  return actions;
}

function createReactionButtons(target, onToggle) {
  const wrap = document.createElement("div");
  wrap.className = "reaction-row";

  reactionTypes.forEach((reaction) => {
    const button = document.createElement("button");
    const count = target.reactions?.[reaction.key] || 0;
    const isActive = target.selectedReaction === reaction.key;
    button.className = `reaction-button${isActive ? " active" : ""}`;
    button.type = "button";
    button.setAttribute("aria-pressed", String(isActive));
    button.setAttribute("aria-label", `${reaction.label} 공감 ${count}개`);
    button.textContent = `${reaction.emoji} ${count}`;
    button.addEventListener("click", () => onToggle(reaction.key));
    wrap.append(button);
  });

  return wrap;
}

function toggleReactionState(target, reactionKey) {
  const reactions = { ...normalizeReactionState(target).reactions };
  const currentReaction = target.selectedReaction || "";

  if (currentReaction === reactionKey) {
    reactions[reactionKey] = Math.max(0, (reactions[reactionKey] || 0) - 1);
    return { ...target, reactions, selectedReaction: "" };
  }

  if (currentReaction) {
    reactions[currentReaction] = Math.max(0, (reactions[currentReaction] || 0) - 1);
  }
  reactions[reactionKey] = (reactions[reactionKey] || 0) + 1;
  return { ...target, reactions, selectedReaction: reactionKey };
}

function toggleAlbumReaction(itemId, reactionKey) {
  albumItems = albumItems.map((item) =>
    item.id === itemId ? toggleReactionState(item, reactionKey) : item
  );
  saveList(keys.album, albumItems);
  renderAlbum();
}

function createCommentArea(item) {
  const wrap = document.createElement("div");
  wrap.className = "comment-area";

  const list = document.createElement("div");
  list.className = "comment-list";

  const comments = [...(item.comments || [])].sort(
    (a, b) => new Date(a.createdAt || 0) - new Date(b.createdAt || 0)
  );

  comments.forEach((comment) => {
    const note = document.createElement("article");
    note.className = "comment-note";
    const text = document.createElement("p");
    text.textContent = comment.text;
    const reactions = createReactionButtons(comment, (reactionKey) => {
      toggleCommentReaction(item.id, comment.id, reactionKey);
    });
    note.append(text, reactions);
    list.append(note);
  });

  const form = document.createElement("form");
  form.className = "comment-form";

  const input = document.createElement("input");
  input.type = "text";
  input.placeholder = "사진 아래에 메모를 남겨 주세요.";
  input.setAttribute("aria-label", "사진 메모");

  const button = document.createElement("button");
  button.className = "button small";
  button.type = "submit";
  button.textContent = "남기기";

  form.append(input, button);
  form.addEventListener("submit", (event) => {
    event.preventDefault();
    addComment(item.id, input.value);
  });

  wrap.append(list, form);
  return wrap;
}

function toggleCommentReaction(itemId, commentId, reactionKey) {
  albumItems = albumItems.map((item) => {
    if (item.id !== itemId) return item;
    return {
      ...item,
      comments: (item.comments || []).map((comment) =>
        comment.id === commentId
          ? toggleReactionState(comment, reactionKey)
          : comment
      ),
    };
  });
  saveList(keys.album, albumItems);
  renderAlbum();
}

function addComment(itemId, text) {
  const comment = text.trim();
  if (!comment) return;

  albumItems = albumItems.map((item) => {
    if (item.id !== itemId) return item;
    return {
      ...item,
      comments: [
        ...(item.comments || []),
        {
          id: makeId(),
          text: comment,
          createdAt: new Date().toISOString(),
          reactions: {},
          selectedReaction: "",
        },
      ],
    };
  });
  saveList(keys.album, albumItems);
  renderAlbum();
}

function getVisibleAlbumItems() {
  const items = [...albumItems].filter(
    (item) => selectedFamily === "all" || item.family === selectedFamily
  );

  if (selectedFamily === "all") {
    return items.sort((a, b) => {
      const popularityDiff = getPopularityScore(b) - getPopularityScore(a);
      if (popularityDiff) return popularityDiff;

      const commentDiff = (b.comments || []).length - (a.comments || []).length;
      if (commentDiff) return commentDiff;

      return new Date(b.createdAt || 0) - new Date(a.createdAt || 0);
    });
  }

  return items.sort((a, b) => new Date(b.createdAt || 0) - new Date(a.createdAt || 0));
}

function renderStoryPhotos() {
  if (!storyPhotoGrid) return;
  storyPhotoGrid.innerHTML = "";

  const recentItems = getVisibleAlbumItems()
    .filter((item) => item.image)
    .slice(0, 6);

  recentItems.forEach((item) => {
    const figure = document.createElement("figure");
    figure.className = "story-photo";

    const img = document.createElement("img");
    img.src = item.image?.startsWith("gradient:") ? "" : item.image;
    img.alt = item.title || `${familyLabels[item.family] || "가족"} 사진`;
    applyImageFallback(img, item);
    if (item.image?.startsWith("gradient:")) {
      figure.style.background = item.image.replace("gradient:", "");
    } else {
      figure.append(img);
    }

    if (item.title || item.date || item.memo) {
      const caption = document.createElement("figcaption");
      caption.textContent = item.title || formatDate(item.date);
      figure.append(caption);
    }

    storyPhotoGrid.append(figure);
  });

  if (!recentItems.length) {
    const empty = document.createElement("article");
    empty.className = "empty-state";
    empty.textContent = "사진을 업로드하면 이곳에 최신순으로 표시됩니다.";
    storyPhotoGrid.append(empty);
  }
}

function renderRecommendations() {
  recommendationGrid.innerHTML = "";

  recommendations.forEach((item) => {
    const card = document.createElement("button");
    card.className = "recommend-card";
    card.type = "button";

    const preview = document.createElement("div");
    preview.className = "recommend-preview";
    if (item.image) {
      const img = document.createElement("img");
      img.src = item.image;
      img.alt = `${item.title} 표지 이미지`;
      applyImageFallback(img, item);
      preview.append(img);
    } else {
      preview.style.background = item.gradient;
    }

    const copy = document.createElement("div");
    const title = document.createElement("strong");
    title.textContent = item.title;
    const text = document.createElement("p");
    text.textContent = item.text;
    copy.append(title, text);

    card.append(preview, copy);
    card.addEventListener("click", () => addCoverToAlbum(item));
    recommendationGrid.append(card);
  });
}

function addCoverToAlbum(item) {
  albumItems = [
    {
      id: makeId(),
      family: selectedFamily === "all" ? "song-soonhee" : selectedFamily,
      title: item.title,
      date: "",
      createdAt: new Date().toISOString(),
      category: item.category,
      customCategory: "",
      memo: `${item.title} 표지를 앨범에 추가했습니다. 실제 사진으로 교체하거나 메모를 보완해 주세요.`,
      image: item.image || `gradient:${item.gradient}`,
      reactions: {},
      selectedReaction: "",
      comments: [],
    },
    ...albumItems,
  ];
  saveList(keys.album, albumItems);
  renderAlbum();
  document.querySelector("#album").scrollIntoView({ behavior: "smooth" });
}

albumForm.addEventListener("submit", (event) => {
  event.preventDefault();

  const title = document.querySelector("#photoTitle").value.trim();
  const file = document.querySelector("#photoFile").files[0];
  const categoryInput = getSelectedCategoryInput();

  if (categoryInput.category === "other" && !categoryInput.customCategory) {
    customCategory.focus();
    return;
  }

  if (!file && !title) {
    document.querySelector("#photoFile").focus();
    return;
  }

  const newItem = {
    id: makeId(),
    family: document.querySelector("#photoFamily").value,
    title,
    date: document.querySelector("#photoDate").value,
    createdAt: new Date().toISOString(),
    category: categoryInput.category,
    customCategory: categoryInput.customCategory,
    memo: document.querySelector("#photoMemo").value.trim(),
    image: "",
    reactions: {},
    selectedReaction: "",
    comments: [],
  };

  if (!file) {
    albumItems = [newItem, ...albumItems];
    saveList(keys.album, albumItems);
    renderAlbum();
    renderStoryPhotos();
    albumForm.reset();
    photoCategory.value = "palsoon";
    customCategory.value = customCategoryPrompt;
    bindCategoryInput();
    return;
  }

  const reader = new FileReader();
  reader.addEventListener("load", () => {
    albumItems = [{ ...newItem, image: reader.result }, ...albumItems];
    saveList(keys.album, albumItems);
    renderAlbum();
    renderStoryPhotos();
    albumForm.reset();
    photoCategory.value = "palsoon";
    customCategory.value = customCategoryPrompt;
    bindCategoryInput();
  });
  reader.readAsDataURL(file);
});

function shareAlbumItem(item) {
  const shareText = item.title
    ? `${item.title} 사진을 가족 앨범에서 확인해 보세요.`
    : "가족 앨범에 새 사진이 올라왔어요.";
  const shareUrl = `${location.origin}${location.pathname}#album`;

  if (navigator.share) {
    navigator
      .share({
        title: item.title || "가족 축하 앨범",
        text: shareText,
        url: shareUrl,
      })
      .catch(() => copyShareLink(shareUrl));
    return;
  }

  copyShareLink(shareUrl);
}

function copyShareLink(url) {
  navigator.clipboard?.writeText(url);
}

function renderLetters() {
  if (!letterList) return;
  letterList.innerHTML = "";

  letters.forEach((letter) => {
    const article = document.createElement("article");
    article.className = "letter-note";

    const author = document.createElement("span");
    author.textContent = letter.from;

    const title = document.createElement("h3");
    title.textContent = "축하 메시지";

    const body = document.createElement("p");
    body.textContent = letter.body;

    article.append(author, title, body);
    letterList.append(article);
  });
}

letterForm?.addEventListener("submit", (event) => {
  event.preventDefault();

  const from = document.querySelector("#letterFrom").value.trim() || "익명의 가족";
  const body = document.querySelector("#letterBody").value.trim();
  if (!body) {
    document.querySelector("#letterBody").focus();
    return;
  }

  letters = [{ id: makeId(), from, body }, ...letters];
  saveList(keys.letters, letters);
  renderLetters();
  letterForm.reset();
});

